import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/orders")
public class OrderController {

    @Autowired
    private OrderService orderService;

    @GetMapping("/{orderId}")
    public ResponseEntity<Order> getOrderDetails(@PathVariable String orderId) {
        // Retrieve the authenticated user from the security context
        User authenticatedUser = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();

        // Check if the authenticated user has access to the order
        if (!orderService.hasAccess(authenticatedUser, orderId)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }

        // Retrieve the order details
        Order orderDetails = orderService.getOrderById(orderId);

        if (orderDetails == null) {
            return ResponseEntity.notFound().build();
        }

        return ResponseEntity.ok(orderDetails);
    }
}